INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-6f0ba476-moex-00091', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '為保障納稅義務人權益，納稅義務人對於稅捐處分如有不服者，可採行政 救濟。下列有關行政救濟之敘述，何者正確？', '["國外輸入之貨物，由海關代徵之稅捐，其徵收及行政救濟程序，準用稅 捐稽徵法及施行細則之規定辦理", "若納稅義務人對於核定稅額通知書所載有應納稅額或應補徵稅額之處 分有不服者，依規定申請復查，應於繳款書送達後，於繳納期間屆滿之 翌日起30日內，申請復查", "納稅義務人對稅捐稽徵機關之復查決定如有不服，得逕依法提起行政訴訟", "納稅義務人經依法提出行政救濟等程序終結決定或判決，應退還稅款 者，稅捐機關應於10日內依退稅額無息退還予納稅義務人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00092', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '綜合所得稅中有關「列舉扣除額」之項目與額度規定，下列何者正確？', '["納稅義務人、配偶或受扶養直系親屬之人身保險、勞工保險、國民年金 保險及軍、公、教保險之保險費，每人每年扣除數額以不超過2萬4千 元為限。但全民健康保險之保險費不受金額限制", "納稅義務人、配偶及受扶養親屬購買自用住宅，向金融機構借款所支付 之利息減除其所申報之儲蓄投資特別扣除額後，其每一申報戶每年扣除 數額以20萬元為限，並以1屋為限", "納稅義務人、配偶或受扶養親屬之薪資所得，每人每年扣除數額以20萬 元為限", "自民國 108 年 1 月 1 日起，納稅義務人、配偶或受扶養親屬為符合 中央衛生福利主管機關公告須長期照顧之身心失能者，每人每年扣除 12萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00093', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '為改善不動產交易稅制缺失，健全不動產稅制，促使房屋、土地交易正常 化，個人及營利事業出售民國105年1月1日以後取得之房屋、土地，其 交易所得應依所得稅法第 14 條之 4 至第 14 條之 8 及第 24 條之 5 規定課 徵所得稅，即所謂房地合一課稅。但為保障自住需求，落實居住正義，個 人與其配偶及未成年子女出售之自住房屋、土地，若符合相關條件者，其 交易所得可免徵所得稅。有關須符合之免稅條件，下列何者正確？', '["都市土地面積不超過1.5公畝，非都市土地面積不超過3.5公畝", "交易前5年內，無出租、供營業或執行業務使用", "個人或其配偶、未成年子女辦竣戶籍登記、持有並居住於該房屋連續滿 6年", "其免稅所得額，以房地交易所得減除當次交易土地漲價總數額後之餘額 不超過600萬元為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00094', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '大陸地區人民於一課稅年度內在臺灣居留合計多少天者，會被視為是中華 民國境內居住之個人？', '["未滿90天", "滿90天，未滿183天", "滿183天", "無論多少天皆不會被認定為中華民國境內居住之個人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00095', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', 'A公司總機構設在高雄市，民國113年度有境內營利事業所得額為新臺幣 6000 萬元，另有美國分公司所得額折合新臺幣為5000 萬元，惟其分公司 已在美國依法繳納所得稅折合新臺幣 1050 萬元，並取得納稅憑證及相關 簽證。試問A公司113年度實際應繳納營利事業所得稅額為何？', '["1200萬元", "1150萬元", "1260萬元", "1050萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00096', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '依現行所得稅法規定，下列何項非屬於綜合所得稅之列舉扣除額？', '["保險費", "災害損失", "購屋借款利息", "房屋租金支出"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00097', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '自民國 107 年 1 月 1 日起，納稅義務人、配偶及符合所得稅法第 17 條規 定得申報之受扶養親屬，獲配營利所得，其屬所投資之公司、合作社及其 他法人分配87年度或以後年度之股利或盈餘，根據所得稅法第15條之規 定，納稅義務人得選擇兩種報繳方式。下列敘述何者正確？', '["得就股利及盈餘合計金額按百分之十計算可抵減稅額，抵減當年度依規 定計算之綜合所得稅結算申報應納稅額，每一申報戶每年抵減金額以12 萬元為限", "申報戶之股利及盈餘合計金額按百分之二十八之稅率分開計算應納稅 額，由納稅義務人合併報繳", "得就股利及盈餘合計金額按百分之五計算可抵減稅額，抵減當年度依規 定計算之綜合所得稅結算申報應納稅額，每一申報戶每年抵減金額以27 萬元為限", "申報戶之股利及盈餘合計金額按百分之十八之稅率分開計算應納稅額， 由納稅義務人合併報繳"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00098', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '陳先生於民國 113 年度出售 100 年 5 月買入之 A 房屋，認列財產交易所 得 100 萬元，惟同年另出售 102 年 10 月取得之房屋發生交易損失 150 萬 元，試問陳先生當年度最多可以申報多少之財產交易損失？', '["0元", "50萬元", "100萬元", "150萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00099', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '營利事業或個人之所得基本稅額部分項目之所得免稅額度，每遇消費者物 價指數較上次調整年度之指數上漲累計達百分之十以上時，按上漲程度調 整之。調整金額以新臺幣10萬元為單位，未達新臺幣10萬元者，按萬元 數四捨五入。根據財政部最新公告114年度所得基本稅額相關免稅額，於 115年5月申報所得稅時適用之金額，下列何者錯誤？', '["個人基本所得額免稅額度為新臺幣750萬元", "營利事業基本所得額免稅額度為新臺幣60萬元", "保險死亡給付每一申報戶全年合計數免稅額度為新臺幣3740萬元", "未計入綜合所得總額之非中華民國來源所得及港澳來源所得，每一申報 戶全年之所得合計數免稅額度為折合新臺幣600萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00100', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '總機構在中華民國境內之營利事業出售房屋、土地之交易所得減除依土地 稅法第 30 條第 1 項規定公告土地現值計算之土地漲價總數額後之餘額， 不併計營利事業所得額，按規定稅率分開計稅，合併報繳。有關其稅率之 規定，下列敘述何者錯誤？', '["持有房屋、土地之期間在2年以內者，稅率為百分之四十", "持有房屋、土地之期間超過2年，未逾5年者，稅率為百分之三十五", "持有房屋、土地之期間超過5年者，稅率為百分之二十", "因財政部公告之非自願性因素，交易持有期間在5年以下之房屋、土地 者，稅率為百分之二十"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
